  1→import { useCallback, useMemo, useState } from 'react';
  2→import { ActionPanel } from './components/action_panel/action_panel';
  3→import { CommandPalette } from './components/command_palette/command_palette';
  4→import { Detail } from './components/detail/detail';
  5→import { DetailMetadata } from './components/detail/detail_metadata';
  6→import { EmptyState } from './components/empty_state/empty_state';
  7→import { Kbd } from './components/kbd/kbd';
  8→import { List, ListItem, ListSection } from './components/list';
  9→import { SearchBar } from './components/search_bar/search_bar';
 10→import { MOCK_SECTIONS } from './data/mock_data';
 11→import type { ListItemData, ListItemMetadataEntry, SectionData } from './types';
 12→
 13→function filterSections(sections: SectionData[], query: string): SectionData[] {
 14→  if (!query) return sections;
 15→  const lower = query.toLowerCase();
 16→  return sections
 17→    .map(section => ({
 18→      ...section,
 19→      items: section.items.filter(
 20→        item =>
 21→          item.title.toLowerCase().includes(lower) ||
 22→          item.subtitle?.toLowerCase().includes(lower),
 23→      ),
 24→    }))
 25→    .filter(section => section.items.length > 0);
 26→}
 27→
 28→function flattenItems(sections: SectionData[]): ListItemData[] {
 29→  return sections.flatMap(s => s.items);
 30→}
 31→
 32→function renderMetadataEntry(entry: ListItemMetadataEntry, index: number) {
 33→  switch (entry.type) {
 34→    case 'label':
 35→      return (
 36→        <DetailMetadata.Label
 37→          key={index}
 38→          title={entry.title}
 39→          text={entry.text}
 40→        />
 41→      );
 42→    case 'link':
 43→      return (
 44→        <DetailMetadata.Link
 45→          key={index}
 46→          title={entry.title}
 47→          text={entry.text}
 48→          target={entry.target}
 49→        />
 50→      );
 51→    case 'tag-list':
 52→      return (
 53→        <DetailMetadata.TagList key={index} title={entry.title}>
 54→          {entry.tags.map(tag => (
 55→            <DetailMetadata.Tag
 56→              key={tag.text}
 57→              text={tag.text}
 58→              color={tag.color}
 59→            />
 60→          ))}
 61→        </DetailMetadata.TagList>
 62→      );
 63→    case 'separator':
 64→      return <DetailMetadata.Separator key={index} />;
 65→  }
 66→}
 67→
 68→function SearchIcon() {
 69→  return (
 70→    <svg
 71→      width="48"
 72→      height="48"
 73→      viewBox="0 0 48 48"
 74→      fill="none"
 75→      xmlns="http://www.w3.org/2000/svg"
 76→    >
 77→      <circle cx="21" cy="21" r="12" stroke="currentColor" strokeWidth="3" />
 78→      <line
 79→        x1="30"
 80→        y1="30"
 81→        x2="42"
 82→        y2="42"
 83→        stroke="currentColor"
 84→        strokeWidth="3"
 85→        strokeLinecap="round"
 86→      />
 87→    </svg>
 88→  );
 89→}
 90→
 91→export function App() {
 92→  const [query, setQuery] = useState('');
 93→  const [selectedIndex, setSelectedIndex] = useState(0);
 94→
 95→  const filtered = useMemo(() => filterSections(MOCK_SECTIONS, query), [query]);
 96→  const allItems = useMemo(() => flattenItems(filtered), [filtered]);
 97→  const selectedItem = allItems[selectedIndex];
 98→
 99→  const handleQueryChange = useCallback((value: string) => {
100→    setQuery(value);
101→    setSelectedIndex(0);
102→  }, []);
103→
104→  const handleActiveIndexChange = useCallback((index: number) => {
105→    setSelectedIndex(index);
106→  }, []);
107→
108→  const detail = selectedItem?.detail;
109→
110→  return (
111→    <CommandPalette>
112→      <SearchBar value={query} onChange={handleQueryChange} />
113→      <div className="command-palette__body">
114→        <div className="command-palette__list-container">
115→          {allItems.length === 0 ? (
116→            <EmptyState
117→              icon={<SearchIcon />}
118→              title="No Results"
119→              description="Try a different search term"
120→            />
121→          ) : (
122→            <List
123→              itemCount={allItems.length}
124→              onActiveIndexChange={handleActiveIndexChange}
125→            >
126→              {(() => {
127→                let globalIndex = 0;
128→                return filtered.map(section => (
129→                  <ListSection key={section.title} title={section.title}>
130→                    {section.items.map(item => {
131→                      const idx = globalIndex++;
132→                      return (
133→                        <ListItem
134→                          key={item.id}
135→                          index={idx}
136→                          title={item.title}
137→                          subtitle={item.subtitle}
138→                          icon={item.icon}
139→                          accessories={item.accessories}
140→                        />
141→                      );
142→                    })}
143→                  </ListSection>
144→                ));
145→              })()}
146→            </List>
147→          )}
148→        </div>
149→        {detail && (
150→          <Detail
151→            markdown={detail.markdown}
152→            metadata={
153→              detail.metadata ? (
154→                <DetailMetadata>
155→                  {detail.metadata.map(renderMetadataEntry)}
156→                </DetailMetadata>
157→              ) : undefined
158→            }
159→          />
160→        )}
161→      </div>
162→      <ActionPanel
163→        actions={[
164→          {
165→            label: 'Open',
166→            shortcut: <Kbd keys={['↵']} />,
167→          },
168→          {
169→            label: 'Actions',
170→            shortcut: (
171→              <Kbd
172→                keys={[
173→                  '⌘',
174→                  'K',
175→                ]}
176→              />
177→            ),
178→          },
179→        ]}
180→      />
181→    </CommandPalette>
182→  );
183→}
