  1→import {
  2→  type ReactNode,
  3→  useCallback,
  4→  useEffect,
  5→  useMemo,
  6→  useRef,
  7→  useState,
  8→} from 'react';
  9→import './list.scss';
 10→import { ListContext } from './list_context';
 11→
 12→interface ListProps {
 13→  children: ReactNode;
 14→  itemCount: number;
 15→  onActiveIndexChange?: (index: number) => void;
 16→  onAction?: (index: number) => void;
 17→}
 18→
 19→export function List({
 20→  children,
 21→  itemCount,
 22→  onActiveIndexChange,
 23→  onAction,
 24→}: ListProps) {
 25→  const [activeIndex, setActiveIndexRaw] = useState(0);
 26→  const containerRef = useRef<HTMLDivElement>(null);
 27→
 28→  const setActiveIndex = useCallback(
 29→    (index: number) => {
 30→      setActiveIndexRaw(index);
 31→      onActiveIndexChange?.(index);
 32→    },
 33→    [onActiveIndexChange],
 34→  );
 35→
 36→  useEffect(() => {
 37→    if (itemCount === 0) {
 38→      setActiveIndex(0);
 39→    } else if (activeIndex >= itemCount) {
 40→      setActiveIndex(itemCount - 1);
 41→    }
 42→  }, [
 43→    itemCount,
 44→    activeIndex,
 45→    setActiveIndex,
 46→  ]);
 47→
 48→  useEffect(() => {
 49→    const container = containerRef.current;
 50→    if (!container) return;
 51→
 52→    const activeElement = container.querySelector<HTMLElement>(
 53→      `[data-list-index="${activeIndex}"]`,
 54→    );
 55→    activeElement?.scrollIntoView({ block: 'nearest' });
 56→  }, [activeIndex]);
 57→
 58→  useEffect(() => {
 59→    function handleKeyDown(e: KeyboardEvent) {
 60→      if (itemCount === 0) return;
 61→      if (e.metaKey || e.ctrlKey || e.altKey) return;
 62→
 63→      if (e.key === 'ArrowDown') {
 64→        e.preventDefault();
 65→        setActiveIndex(activeIndex < itemCount - 1 ? activeIndex + 1 : 0);
 66→      } else if (e.key === 'ArrowUp') {
 67→        e.preventDefault();
 68→        setActiveIndex(activeIndex > 0 ? activeIndex - 1 : itemCount - 1);
 69→      } else if (e.key === 'Enter') {
 70→        e.preventDefault();
 71→        onAction?.(activeIndex);
 72→      }
 73→    }
 74→
 75→    window.addEventListener('keydown', handleKeyDown);
 76→    return () => window.removeEventListener('keydown', handleKeyDown);
 77→  }, [
 78→    activeIndex,
 79→    itemCount,
 80→    setActiveIndex,
 81→    onAction,
 82→  ]);
 83→
 84→  const contextValue = useMemo(
 85→    () => ({
 86→      activeIndex,
 87→      setActiveIndex,
 88→    }),
 89→    [
 90→      activeIndex,
 91→      setActiveIndex,
 92→    ],
 93→  );
 94→
 95→  return (
 96→    <ListContext value={contextValue}>
 97→      <div ref={containerRef} className="list" role="listbox">
 98→        {children}
 99→      </div>
100→    </ListContext>
101→  );
102→}
